#!/usr/bin/env bash
# b.sh — B 端政府采购 / 招投标 / 履约全流程（含合规与廉政红线） SOP walkthrough for 研学营地教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="研学营地教育"
WORKFLOW="B 端政府采购 / 招投标 / 履约全流程（含合规与廉政红线）"

usage() {
  cat <<EOF
b.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./b.sh             # interactive
  ./b.sh --dry-run
  ./b.sh --json
  ./b.sh --explain
  ./b.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "B 端政府采购 / 招投标 / 履约全流程（含合规与廉政红线）" 工作流。

一句话: 从「教育局/学校发布研学采购或自主遴选承办方」走到「合规中标、按约履约、结算留痕、进入并留在服务机构名录」的状态——研学机构 B 端营收的获取通道，也是合规与廉政红线最密的一环。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 「研学是课程不是行程」——教育属性优先: 研学/营地的本体是**课程**（有学习目标—实施—评价闭环），不是**行程**（景点+讲解词）；从业者用「教育本质」作为对抗旅游化、获客化、速成化的立场锚与对客叙事。
  • 体验—反思闭环（Kolb 圈）——「经验无反思即旅游」: 学习不是「去过/动手过」就发生，而要走完「具体经验→反思观察→抽象概念化→主动实践」的圈；**「反思/复盘」环节的有无，是研学区别于旅游的命门工序**。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**资格/名录前置**：备齐《旅行社业务经营许可证》+营业执照/财务审计等，**进入省级研学服务机构名录**（如黑龙江省名录原则上每 2 年遴选 1 次、有效期 2 年）；确认近三年无重大安全事故/质量投诉/不良诚信。跳过后果：无名录资格直接失去投标权，或资格审查被废标。 evidence: [W-S007, W-S006]"
  "**响应招标方式**：研学采购多用**竞争性磋商/竞争性谈判/询价**（非最低价中标），按需求书做方案+报价响应。跳过后果：方案不响应需求书要点，技术分被压垮。 evidence: [W-S006, W-S017]"
  "**方案设计+报价**：按需求书做课程+安全+保险+服务标准方案（即 W1/W3/W4 成果打包），报价含合理成本结构。跳过后果：低价中标后无法合规履约（师资/安全缩水），埋雷。 evidence: [W-S006]"
  "**评标响应**：评标小组含校领导/干部/教师+**家长代表（教师与家长代表≥60%）**，技术与教育性是关键分。跳过后果：只拼价格不拼教育性，在「教师+家长占多数」的评标结构里出局。 evidence: [W-S006]"
  "**中标履约**：按 W1 全流程合规执行，**不得转委托给未进名录的机构**。跳过/违规后果：转包、缩水即违约，且可能被从名录除名。 evidence: [W-S007]"
  "**结算+留痕**：按合同结算，全程材料归档留存（应对审计与监管核查）。跳过后果：核查无据、结算纠纷、信誉与名录受损。 evidence: [W-S005, W-S007]"
)
declare -a FAILURE_MODES=(
  "**低价中标后履约缩水**：为抢标报超低价，履约时砍师资/砍安全/砍保险，出事或被投诉→被除名。→ 守成本底线，用教育性+安全方案竞争（采购本就是竞争性磋商非最低价）。 evidence: [W-S006]"
  "**无名录资格/转包给名录外机构**：没进名录还投标，或中标后转包给未入名录机构，资格审查废标或违约除名。→ 名录资格前置+不转委托名录外机构。 evidence: [W-S007]"
  "**廉政红线翻车**：研学采购涉财政经费与校长权力，违规采购/回扣一旦曝光，机构与校方双输、永久出局。→ 全过程廉政留痕+利益冲突隔离+尊重家长代表评标机制。 evidence: [W-S006]"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "b-walkthrough"
fi
